import json as _json

async def execute(self, inputs):
    from src.utils.hou_bridge import get_bridge

    node_path = inputs.get('node_path') or self.get_parameter('node_path', '')
    parms = inputs.get('parms') or self.get_parameter('parms', '{}')

    if isinstance(parms, str):
        try:
            parms = _json.loads(parms)
        except _json.JSONDecodeError as e:
            self.log_error(f'Invalid JSON for parms: {e}')
            await self.set_output('success', False)
            await self.set_output('exec_out', True)
            return {'success': False}

    if not node_path or not parms:
        self.log_error('Node path and parms dict are required')
        await self.set_output('success', False)
        await self.set_output('exec_out', True)
        return {'success': False}

    try:
        bridge = get_bridge()
        bridge.set_parms(node_path, parms)
        self.log_info(f'Set {len(parms)} parms on {node_path}')
        await self.set_output('success', True)
    except Exception as e:
        self.log_error(f'Failed to set parms: {e}')
        await self.set_output('success', False)

    await self.set_output('exec_out', True)
    return {'success': self.get_parameter('success', False)}
